import React, { useReducer, useEffect, useState } from 'react';

// Zustandsverwaltung nach dem Reducer-Prinzip [cite: 2188, 2216]
const initialState = { projects: [], selectedProject: null, tasks: [], status: 'idle' };

function reducer(state, action) {
    switch (action.type) {
        case 'SET_PROJECTS': return { ...state, projects: action.payload, status: 'success' };
        case 'SELECT_PROJECT': return { ...state, selectedProject: action.payload, tasks: [] };
        case 'SET_TASKS': return { ...state, tasks: action.payload };
        case 'UPDATE_TASK':
            return { ...state, tasks: state.tasks.map(t => t.id === action.payload.id ? action.payload : t) };
        default: return state;
    }
}

export default function App() {
    const [state, dispatch] = useReducer(reducer, initialState);
    const [loading, setLoading] = useState(false);

    // Authentifizierungs-Header (Beispielhaft für Basic Auth) [cite: 972, 1014]
    const authHeader = { 'Authorization': 'Basic ' + btoa('manager:password'), 'Content-Type': 'application/json' };

    useEffect(() => { loadProjects(); }, []);

    const loadProjects = async () => {
        const res = await fetch('http://localhost:8080/api/projects', { headers: authHeader });
        const data = await res.json();
        dispatch({ type: 'SET_PROJECTS', payload: data });
    };

    const selectProject = async (project) => {
        dispatch({ type: 'SELECT_PROJECT', payload: project });
        // In einer echten App würdest du hier GET /api/tasks?projectId=... aufrufen
        // Wir simulieren hier den Abruf für die Demo
    };

    const handleStatusChange = async (taskId, newStatus) => {
        // PATCH-Methode für partielle Updates [cite: 621, 1110]
        const res = await fetch(`http://localhost:8080/api/tasks/${taskId}/status?status=${newStatus}`, {
            method: 'PATCH',
            headers: authHeader
        });
        if (res.ok) {
            const updatedTask = await res.json();
            dispatch({ type: 'UPDATE_TASK', payload: updatedTask });
        }
    };

    return (
        <div style={{ display: 'flex', gap: '2rem', padding: '2rem', fontFamily: 'sans-serif' }}>
        {/* Linke Seite: Projektliste */}
        <section style={{ flex: 1 }}>
        <h2>Kundenprojekte</h2>
        {state.projects.map(p => (
            <div key={p.id}
            onClick={() => selectProject(p)}
            style={{ padding: '1rem', border: '1px solid #ccc', marginBottom: '0.5rem', cursor: 'pointer',
                backgroundColor: state.selectedProject?.id === p.id ? '#e0e0e0' : 'white' }}>
                <strong>{p.name}</strong> <br/>
                <small>Status: {p.status}</small>
                </div>
        ))}
        </section>

        {/* Rechte Seite: Aufgaben-Details */}
        <section style={{ flex: 2, borderLeft: '2px solid #eee', paddingLeft: '2rem' }}>
        {state.selectedProject ? (
            <>
            <h2>Aufgaben für: {state.selectedProject.name}</h2>
            {/* Hier würden die Aufgaben gelistet, die zum Projekt gehören */}
            <div style={{ border: '1px solid #ddd', padding: '1rem', borderRadius: '8px' }}>
            <p>Beispielaufgabe: Backend-API implementieren</p>
            <p>Aktueller Status: <strong>OPEN</strong></p>

            {/* Status-Buttons für Mitarbeiter [cite: 153, 1168] */}
            <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button onClick={() => handleStatusChange(1, 'IN_PROGRESS')}>In Bearbeitung</button>
            <button onClick={() => handleStatusChange(1, 'DONE')}>Erledigt</button>
            </div>
            </div>
            </>
        ) : (
            <p>Bitte wählen Sie links ein Projekt aus, um Details zu sehen.</p>
        )}
        </section>
        </div>
    );
}
